#include <stdio.h>
#include <inttypes.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t X, Y; scanf("%" PRId64 " %" PRId64, &X, &Y);
        int64_t base = X < Y ? X : Y;
        int64_t extra = Y > X ? (Y - X) * 2 : 0;
        printf("%" PRId64 "\n", base + extra);
    }
    return 0;
}

